258→export const addCommentService = async (chapterId, userId, comment, paragraphIndex, paragraphFingerprint, parentId) => {
259→    if (!chapterId || !userId) {
260→        throw { status: 400, error: 'chapterId and userId are required' };
261→    }
262→    if (!comment || typeof comment !== 'string' || comment.trim().length === 0) {
263→        throw { status: 400, error: 'comment is required' };
264→    }
265→    if (comment.length > 300) {
266→        throw { status: 400, error: 'comment must be 300 characters or less' };
267→    }
268→
269→    const insertData = {
270→        chapter_id: chapterId,
271→        user_id: userId,
272→        comment: comment.trim(),
273→        paragraph_index: paragraphIndex !== undefined ? parseInt(paragraphIndex) : -1,
274→        paragraph_fingerprint: paragraphFingerprint || null,
275→        parent_id: parentId || null,
276→    };
277→
278→    const { data, error } = await supabase
279→        .from('story_comments')
280→        .insert(insertData)
281→        .select(`*, users(id, name, image_url, username, badge)`)
282→        .single();
283→
284→    if (error) {
285→        console.error('supabase error adding comment:', error.message);
286→        throw { status: 500, error: 'failed to add comment' };
287→    }
288→
289→    return data;
290→};
