292→// ── Reading Progress ──
293→export const saveProgressService = async (storyId, userId, chapterId, scrollPosition) => {
294→    if (!storyId || !userId || !chapterId) {
295→        throw { status: 400, error: 'storyId, userId, and chapterId are required' };
296→    }
297→
298→    // Check if this is a new reader (no existing progress for this user+story)
299→    const { data: existing } = await supabase
300→        .from('reading_progress')
301→        .select('id')
302→        .eq('user_id', userId)
303→        .eq('story_id', storyId)
304→        .maybeSingle();
305→
306→    const { data, error } = await supabase
307→        .from('reading_progress')
308→        .upsert({
309→            user_id: userId,
310→            story_id: storyId,
311→            chapter_id: chapterId,
312→            scroll_position: scrollPosition || 0,
313→            last_read_at: new Date().toISOString(),
314→        }, { onConflict: 'user_id,story_id' })
315→        .select('*')
316→        .single();
317→
318→    if (error) {
319→        console.error('supabase error saving progress:', error.message);
320→        throw { status: 500, error: 'failed to save progress' };
321→    }
322→
323→    // Increment read_count if this is a new reader (skip if author)
324→    if (!existing) {
325→        const { data: story } = await supabase
326→            .from('stories')
327→            .select('author_id')
328→            .eq('id', storyId)
329→            .single();
330→
331→        if (story && story.author_id !== userId) {
332→            const { error: rpcError } = await supabase.rpc('increment_story_reads', { story_id_input: storyId });
333→            if (rpcError) {
334→                console.error('error incrementing story reads:', rpcError.message);
335→            }
336→        }
337→    }
338→
339→    return data;
340→};
