  1→import React from 'react';
  2→import { useNavigate, useParams } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useStoryDetail } from '../hooks/useStoryData';
  5→import { useToggleVote, useToggleLibrary } from '../hooks/useStoryMutations';
  6→import { motion } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryDetail.css';
  9→
 10→const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
 11→
 12→const StoryDetail = () => {
 13→    const { storyId } = useParams();
 14→    const navigate = useNavigate();
 15→    const { session, openAuthModal } = useAuth();
 16→    const token = session?.access_token;
 17→
 18→    const { data: story, isLoading } = useStoryDetail(storyId, token);
 19→    const voteMutation = useToggleVote(token);
 20→    const libraryMutation = useToggleLibrary(token);
 21→
 22→    const handleVote = () => {
 23→        if (!session) return openAuthModal();
 24→        voteMutation.mutate(storyId);
 25→    };
 26→
 27→    const handleLibrary = () => {
 28→        if (!session) return openAuthModal();
 29→        libraryMutation.mutate(storyId);
 30→    };
 31→
 32→    const handleStartReading = () => {
 33→        // If there's reading progress, resume from there
 34→        if (story?.reading_progress?.chapter_id) {
 35→            navigate(`/home/stories/${storyId}/chapter/${story.reading_progress.chapter_id}`, {
 36→                state: { scrollPosition: story.reading_progress.scroll_position }
 37→            });
 38→            return;
 39→        }
 40→        // Otherwise start from first published chapter
 41→        const firstChapter = story?.chapters?.[0];
 42→        if (firstChapter) {
 43→            navigate(`/home/stories/${storyId}/chapter/${firstChapter.id}`);
 44→        }
 45→    };
 46→
 47→    if (isLoading) {
 48→        return (
 49→            <div className="story-detail">
 50→                <div className="story-detail-loading">
 51→                    <BeatLoader size={10} color="var(--text-muted)" />
 52→                </div>
 53→            </div>
 54→        );
 55→    }
 56→
 57→    if (!story) {
 58→        return (
 59→            <div className="story-detail">
 60→                <p className="story-detail-error">Story not found.</p>
 61→            </div>
 62→        );
 63→    }
 64→
 65→    const author = story.users;
 66→    const chapters = story.chapters || [];
 67→    const hasProgress = !!story.reading_progress;
 68→    const totalWords = chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0);
 69→
 70→    return (
 71→        <motion.div
 72→            className="story-detail"
 73→            initial={{ opacity: 0 }}
 74→            animate={{ opacity: 1 }}
 75→            transition={{ duration: 0.2 }}
 76→        >
 77→            {/* Back button header */}
 78→            <div className="story-detail-header">
 79→                <button className="story-detail-back" onClick={() => navigate(-1)}>
 80→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
 81→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 82→                    </svg>
 83→                </button>
 84→                <span className="story-detail-header-label">Stories</span>
 85→            </div>
 86→
 87→            {/* Hero section */}
 88→            <div className="story-detail-hero">
 89→                <div className="story-detail-cover">
 90→                    {story.cover_url ? (
 91→                        <img src={story.cover_url} alt={story.title} />
 92→                    ) : (
 93→                        <div className="story-detail-cover-placeholder">
 94→                            <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="var(--text-muted)">
 95→                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 96→                            </svg>
 97→                        </div>
 98→                    )}
 99→                </div>
100→                <div className="story-detail-hero-info">
101→                    <h1 className="story-detail-title">{story.title}</h1>
102→                    {author && (
103→                        <div
104→                            className="story-detail-author"
105→                            onClick={() => author.username ? navigate(`/u/${author.username}`) : null}
106→                        >
107→                            {author.image_url && (
108→                                <img src={author.image_url} alt="" className="story-detail-author-avatar" />
109→                            )}
110→                            <span className="story-detail-author-name">{author.name}</span>
111→                        </div>
112→                    )}
113→                    <div className="story-detail-stats">
114→                        <span className={`story-status-badge story-status-${story.status}`}>
115→                            {STATUS_LABELS[story.status] || story.status}
116→                        </span>
117→                        <span>{chapters.length} chapter{chapters.length !== 1 ? 's' : ''}</span>
118→                        <span>{totalWords.toLocaleString()} words</span>
119→                        <span>{(story.read_count || 0).toLocaleString()} reads</span>
120→                        <span>{(story.vote_count || 0).toLocaleString()} votes</span>
121→                    </div>
122→                    {story.tags && story.tags.length > 0 && (
123→                        <div className="story-detail-tags">
124→                            {story.tags.map(tag => (
125→                                <span key={tag} className="story-detail-tag">{tag}</span>
126→                            ))}
127→                        </div>
128→                    )}
129→                </div>
130→            </div>
131→
132→            {/* Action buttons */}
133→            <div className="story-detail-actions">
134→                {chapters.length > 0 && (
135→                    <button className="story-detail-read-btn" onClick={handleStartReading}>
136→                        {hasProgress ? 'Continue Reading' : 'Start Reading'}
137→                    </button>
138→                )}
139→                <button
140→                    className={`story-detail-vote-btn ${story.has_voted ? 'story-detail-vote-btn-active' : ''}`}
141→                    onClick={handleVote}
142→                >
143→                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.has_voted ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
144→                        <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
145→                    </svg>
146→                    {story.vote_count || 0}
147→                </button>
148→                <button
149→                    className={`story-detail-library-btn ${story.in_library ? 'story-detail-library-btn-active' : ''}`}
150→                    onClick={handleLibrary}
151→                >
152→                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.in_library ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
153→                        <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/>
154→                    </svg>
155→                    {story.in_library ? 'In Library' : 'Add to Library'}
156→                </button>
157→            </div>
158→
159→            {/* Description */}
160→            {story.description && (
161→                <div className="story-detail-description">
162→                    <h3>About</h3>
163→                    <p>{story.description}</p>
164→                </div>
165→            )}
166→
167→            {/* Chapter list */}
168→            <div className="story-detail-chapters">
169→                <h3>Chapters ({chapters.length})</h3>
170→                {chapters.length === 0 ? (
171→                    <p className="story-detail-no-chapters">No chapters published yet.</p>
172→                ) : (
173→                    <div className="story-detail-chapter-list">
174→                        {chapters.map((ch) => (
175→                            <div
176→                                key={ch.id}
177→                                className="story-detail-chapter-item"
178→                                onClick={() => navigate(`/home/stories/${storyId}/chapter/${ch.id}`)}
179→                            >
180→                                <div className="story-detail-chapter-left">
181→                                    <span className="story-detail-chapter-number">Ch. {ch.chapter_number}</span>
182→                                    <span className="story-detail-chapter-title">{ch.title}</span>
183→                                </div>
184→                                <div className="story-detail-chapter-right">
185→                                    <span className="story-detail-chapter-words">{(ch.word_count || 0).toLocaleString()} words</span>
186→                                </div>
187→                            </div>
188→                        ))}
189→                    </div>
190→                )}
191→            </div>
192→        </motion.div>
193→    );
194→};
195→
196→export default StoryDetail;
